const source = $json;
const keyPoints = Array.isArray(source.metadata?.key_points) ? source.metadata.key_points : [];
const ukrainianAnalysis = [
  source.summary ? `Українське резюме: ${source.summary}` : '',
  keyPoints.length ? `Ключові моменти українською:\n${keyPoints.map((point) => `- ${point}`).join('\n')}` : ''
].filter(Boolean).join('\n\n');
const body = [ukrainianAnalysis, String(source.content || source.summary || source.title || '').trim()].filter(Boolean).join('\n\n');
const chunkSize = 900;
const overlap = 150;
const chunks = [];
let start = 0;

while (start < body.length) {
  let end = Math.min(start + chunkSize, body.length);
  if (end < body.length) {
    const breakAt = Math.max(body.lastIndexOf('\n', end), body.lastIndexOf(' ', end));
    if (breakAt > start + Math.floor(chunkSize * 0.6)) end = breakAt;
  }
  const part = body.slice(start, end).trim();
  if (part) chunks.push(part);
  if (end >= body.length) break;
  start = Math.max(end - overlap, start + 1);
}

if (chunks.length === 0) chunks.push(String(source.title || 'Untitled'));

return chunks.map((part, chunkIndex) => ({ json: {
  ...source,
  chunk_index: chunkIndex,
  chunk_count: chunks.length,
  chunk_content: [
    `Title: ${source.title}`,
    source.summary ? `Summary: ${source.summary}` : '',
    `Content: ${part}`
  ].filter(Boolean).join('\n')
} }));

const indexed = $input.all();
const first = $('Persist Chunks').first().json;
return [{ json: {
  job_id: first.job_id,
  inbox_item_id: first.inbox_item_id,
  knowledge_item_id: first.knowledge_item_id,
  chunk_count: Number(first.chunk_count || indexed.length),
  indexed_documents: indexed.length
} }];
